const map = {};

for (const item of items) {
  const p = item.json;

  if (!p.id || !p.categories?.length) continue;

  map[p.id] = {
    category_id: p.categories[0].id,
    category_name: p.categories[0].name
  };
}

// Fees bucket
map["fee"] = {
  category_id: 99,
  category_name: "Fees"
};

return [{ json: map }];

// Read inputs
const granularity = ($json.granularity || 'days').toLowerCase();
const now = new Date();

let period_start, period_end;
let prev_period_start, prev_period_end;

// Helper: start of today (UTC – morning)
const startOfTodayUTC = new Date(Date.UTC(
  now.getUTCFullYear(),
  now.getUTCMonth(),
  now.getUTCDate(),
  0, 0, 0
));

// DAILY – TEST MODE (UPDATED)
// DAILY – SAFE TEST MODE (Woo-friendly)
if (granularity === 'days') {

  // Current Period = Yesterday 00:00 UTC → now
  period_end = now;

  period_start = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate() - 1, //  buffer
    0, 0, 0
  ));

  // Previous Period = 6 days before current start
  prev_period_end = new Date(period_start);
  prev_period_start = new Date(prev_period_end);
  prev_period_start.setUTCDate(prev_period_start.getUTCDate() - 6);
}


// WEEKLY – calendar weeks
else if (granularity === 'weekly') {
  const day = now.getUTCDay(); // 0 = Sunday
  const diffToMonday = (day + 6) % 7;

  period_end = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate() - diffToMonday,
    0, 0, 0
  ));

  period_start = new Date(period_end);
  period_start.setUTCDate(period_start.getUTCDate() - 7);

  prev_period_end = new Date(period_start);
  prev_period_start = new Date(prev_period_end);
  prev_period_start.setUTCDate(prev_period_start.getUTCDate() - 7);
}

//  MONTHLY – calendar months
else if (granularity === 'monthly') {
  period_end = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    1,
    0, 0, 0
  ));

  period_start = new Date(period_end);
  period_start.setUTCMonth(period_start.getUTCMonth() - 1);

  prev_period_end = new Date(period_start);
  prev_period_start = new Date(prev_period_end);
  prev_period_start.setUTCMonth(prev_period_start.getUTCMonth() - 1);
}

// Safety
else {
  throw new Error(`Unsupported granularity: ${granularity}`);
}

//  Output
return [
  {
    json: {
      granularity,
      period_start: period_start.toISOString(),
      period_end: period_end.toISOString(),
      prev_period_start: prev_period_start.toISOString(),
      prev_period_end: prev_period_end.toISOString(),
      top_categories_limit: $json.top_categories_limit || 8
    }
  }
];

// Initialize output array
const newItems = [];

// Loop through all items from previous node
for (const item of items) {
    const order = item.json; // actual order object

    const orderInfo = {
        order_id: order.id,
        order_number: order.number,
        order_total: parseFloat(order.total),
        order_date: order.date_created,
        currency: order.currency,
        customer_id: order.customer_id,
        billing_name: `${order.billing.first_name} ${order.billing.last_name}`,
        shipping_name: `${order.shipping.first_name} ${order.shipping.last_name}`,
    };

    // Use line_items if present, else fee_lines
    const itemsList = (order.line_items && order.line_items.length > 0)
        ? order.line_items
        : (order.fee_lines && order.fee_lines.length > 0 ? order.fee_lines : []);

    if (itemsList.length === 0) continue; // skip empty orders

    for (const itemLine of itemsList) {
        newItems.push({
            json: {
                ...orderInfo,
                item_id: itemLine.id,
                item_name: itemLine.name,
                item_qty: itemLine.quantity || 1,
                item_total: parseFloat(itemLine.total || itemLine.amount || 0),
                item_price: parseFloat(itemLine.price || itemLine.amount || 0),
                item_type: (order.line_items && order.line_items.length > 0) ? 'product' : 'fee'
            }
        });
    }
}

return newItems;

