/* ======================================
   INPUTS
   ====================================== */

// Get current and previous normalized rows
const currentRows = $items("Normalize Order Items — Current").map(i => i.json);
const previousRows = $items("Normalize Order Items — Previous").map(i => i.json);

// Get Product → Category map if exists (optional)
const productCategoryMapInput = $items("Category Map")?.[0]?.json || {};

/* ======================================
   BUILD DYNAMIC PRODUCT → CATEGORY MAP
   ====================================== */

const productCategoryMap = { ...productCategoryMapInput };

// Scan current and previous rows for products and add unmapped ones dynamically
for (const row of [...currentRows, ...previousRows]) {
  if (row.item_type === "product" && !productCategoryMap[row.item_id]) {
    // Dynamically create category for unmapped product
    // Replace this with actual logic to fetch from WooCommerce if needed
    // For now, we use "Unmapped" for any missing product
    productCategoryMap[row.item_id] = {
      category_id: row.item_id, // temporary: use product_id as category_id
      category_name: row.item_name // temporary: use product_name as category_name
    };
  }
}

// Always include fees bucket
productCategoryMap["fee"] = { category_id: 99, category_name: "Fees" };

/* ======================================
   HELPER: AGGREGATE ROWS BY CATEGORY
   ====================================== */
function aggregate(rows) {
  const agg = {};

  for (const r of rows) {
    const key = r.item_type === "fee" ? "fee" : r.item_id;
    const cat = productCategoryMap[key] || { category_id: "unmapped", category_name: "Unmapped" };
    const cid = String(cat.category_id);

    if (!agg[cid]) {
      agg[cid] = {
        category_id: cid,
        category_name: cat.category_name,
        revenue: 0,
        units_sold: 0,
        orders: new Set()
      };
    }

    agg[cid].revenue += Number(r.item_total || 0);
    agg[cid].units_sold += Number(r.item_qty || 0);
    agg[cid].orders.add(r.order_id);
  }

  // Convert orders Set → number
  for (const c of Object.values(agg)) {
    c.orders = c.orders.size;
  }

  return agg;
}

/* ======================================
   AGGREGATE CURRENT & PREVIOUS
   ====================================== */
const curAgg = aggregate(currentRows);
const prevAgg = aggregate(previousRows);

// Combine all category IDs
const allCategoryIds = new Set([...Object.keys(curAgg), ...Object.keys(prevAgg)]);

// Total current revenue for share_of_total
const totalCurrentRevenue = Object.values(curAgg).reduce((s, c) => s + c.revenue, 0);

/* ======================================
   BUILD FINAL OUTPUT
   ====================================== */
const result = [];

for (const cid of allCategoryIds) {
  const cur = curAgg[cid] || { revenue: 0, units_sold: 0, orders: 0, category_name: prevAgg[cid]?.category_name || "Unmapped" };
  const prev = prevAgg[cid] || { revenue: 0, units_sold: 0, orders: 0, category_name: cur.category_name };

  const abs_change = cur.revenue - prev.revenue;
  const pct_change = prev.revenue === 0 ? "n/a" : ((abs_change / prev.revenue) * 100).toFixed(2);
  const share_of_total = totalCurrentRevenue === 0 ? "0.00" : ((cur.revenue / totalCurrentRevenue) * 100).toFixed(2);

  result.push({
    category_id: cid,
    category_name: cur.category_name,
    revenue_current: cur.revenue,
    revenue_prev: prev.revenue,
    abs_change,
    pct_change,
    units_sold: cur.units_sold,
    orders_current: cur.orders,
    share_of_total
  });
}

/* ======================================
   RETURN ITEMS FOR N8N
   ====================================== */
return result.map(r => ({ json: r }));

const categories = $items("Aggregate Sales by Category").map(i => i.json);

// Sort categories by revenue_current descending
categories.sort((a, b) => b.revenue_current - a.revenue_current);

// Only categories with positive current revenue
const positiveRevenueCategories = categories.filter(c => c.revenue_current > 0);
const totalPositive = positiveRevenueCategories.length;

// Generate rank map
const rankMap = {};
positiveRevenueCategories.forEach((c, idx) => {
    rankMap[c.category_id] = idx;
});

// Dynamic thresholds
const thresholds = {
    top: 0.2,      // top 20%
    momentum: 0.5, // top 50%
    steady: 0.8    // top 80%
};

categories.forEach(cat => {
    let tag = "";
    let recommended_action = "";

    if (cat.revenue_current === 0 && cat.revenue_prev > 0) {
        // Category had revenue before but 0 now
        tag = "Consider Discontinue";
        recommended_action = "Investigate returns or delisting";
    } else if (cat.revenue_current === 0 && cat.revenue_prev === 0) {
        // Category never sold
        tag = "At Risk";
        recommended_action = "Promotions or marketing";
    } else {
        // Category has revenue now (revenue_current > 0)
        const rank = rankMap[cat.category_id];
        const rankPercent = totalPositive > 1 ? (rank + 1) / totalPositive : 0;

        if (rankPercent <= thresholds.top) {
            tag = "Top Performer";
            recommended_action = "Feature on homepage";
        } else if (rankPercent <= thresholds.momentum) {
            tag = "Momentum";
            recommended_action = "Investigate increasing stock";
        } else if (rankPercent <= thresholds.steady) {
            tag = "Steady";
            recommended_action = "Maintain current strategy";
        } else {
            tag = "At Risk";
            recommended_action = "Promotions or marketing";
        }
    }

    cat.tag = tag;
    cat.recommended_action = recommended_action;
});

return categories.map(c => ({ json: c }));

// Airtable rows come as: item.fields
const rows = items.map(i => i.json.fields);

// Helpers
const formatMoney = (v) =>
  typeof v === "number" ? `₹${v.toLocaleString("en-IN")}` : "₹0";

// Split categories
const top = rows
  .filter(r => r["Current Revenue"] > 0)
  .sort((a, b) => b["Current Revenue"] - a["Current Revenue"])
  .slice(0, 5);

const risk = rows.filter(r =>
  ["At Risk", "Consider Discontinue"].includes(r["Tag"])
);

// Build text
let text = `*Category Performance Summary*\n\n`;

text += `*Top Categories*\n`;
if (top.length === 0) {
  text += `• No sales in current period\n`;
} else {
  for (const r of top) {
    const prev = r["Previous Revenue"];
    const curr = r["Current Revenue"];

    const pct =
      prev > 0
        ? `${(((curr - prev) / prev) * 100).toFixed(1)}%`
        : "n/a";

    text += `• *Category ${r["Category Id"]}* — ${formatMoney(curr)} (${pct}) | ${r["Tag"]}\n`;
  }
}

if (risk.length) {
  text += `\n *Needs Attention*\n`;
  for (const r of risk) {
    text += `• *Category ${r["Category Id"]}* — ${formatMoney(
      r["Current Revenue"]
    )} | ${r["Action "]}\n`;
  }
}

text += `\n Full report available in Airtable.`;

return [{ json: { text } }];
